// Parse the incoming Slack event and decide how to route it
const body = $input.first().json.body || {};
const eventType = body.type || '';

if (eventType === 'url_verification') {
  return [{ json: { route: 'challenge', challenge: body.challenge || '' } }];
}

const event = body.event || {};

// Ignore all bot messages to prevent loops
if (event.bot_id || event.subtype === 'bot_message') {
  return [{ json: { route: 'ignore' } }];
}

const CHANNEL_MAP = {
  'C0AKJ76RE7R': 'kevin',     // counsel-kevin
  'C0ALCHR9A3B': 'jason',     // counsel-jason
  'C0AKJ7918JK': 'scaachi',  // counsel-scaachi
  'C0AKW7VNHHB': 'christian', // counsel-christian
  'C0AKZLG3VFU': 'chidi',    // counsel-chidi
  'C0AKXJSTRV4': 'kevin',     // tasks-kevin
  'C0ALTUECBU0': 'jason',     // tasks-jason
  'C0AKT93TZAP': 'scaachi',  // tasks-scaachi
  'C0AKJ783FF1': 'christian', // tasks-christian
  'C0AKJ787K7H': 'chidi'     // tasks-chidi
};

const TASKS_CHANNELS = new Set([
  'C0AKXJSTRV4', 'C0ALTUECBU0', 'C0AKT93TZAP', 'C0AKJ783FF1', 'C0AKJ787K7H'
]);

const MODEL_MAP = {
  kevin: 'kevin:latest', jason: 'jason:latest', scaachi: 'scaachi:latest',
  christian: 'christian:latest', chidi: 'chidi:latest'
};

const channelId = event.channel || '';
const userId = event.user || '';
const rawText = event.text || '';
const ts = event.ts || event.event_ts || '';
const agent = CHANNEL_MAP[channelId] || 'kevin';
const model = MODEL_MAP[agent];

// Handle @mentions
if (event.type === 'app_mention') {
  const userText = rawText.replace(/<@[A-Z0-9]+>/g, '').trim();

  // Structured TASK: in tasks channels → forward to Tasks Channel Handler (full Linear + studio loop)
  const taskMatch = userText.match(/TASK:\s*(.+?)(?=\nCONTEXT:|\nPRIORITY:|$)/is);
  if (taskMatch && TASKS_CHANNELS.has(channelId)) {
    return [{ json: { route: 'task', body, channelId, userId, ts } }];
  }

  // Regular @mention — inline Ollama response
  return [{ json: { route: 'mention', channelId, userId, rawText, userText, prompt: userText, ts, agent, model } }];
}

// Plain messages in tasks channels with TASK: prefix → forward to Tasks Channel Handler
if (event.type === 'message' && TASKS_CHANNELS.has(channelId)) {
  const taskMatch = rawText.match(/^TASK:\s*(.+?)(?=\nCONTEXT:|\nPRIORITY:|$)/is);
  if (!taskMatch) {
    return [{ json: { route: 'ignore' } }];
  }
  return [{ json: { route: 'task', body, channelId, userId, ts } }];
}

// Handle #the-council — forward to Council Deliberation Engine
if (channelId === 'C0AKVJ5PHHR' && event.type === 'message') {
  return [{ json: { route: 'council', body, channelId, userId, ts } }];
}

// All other events: just ack
return [{ json: { route: 'ignore' } }];

// Convert common markdown to Slack mrkdwn
function mdToMrkdwn(text) {
  return text
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')      // headings → bold
    .replace(/\*\*(.+?)\*\*/gs, '*$1*')          // **bold** → *bold*
    .replace(/__(.+?)__/gs, '*$1*')              // __bold__ → *bold*
    .replace(/~~(.+?)~~/gs, '~$1~')             // ~~strike~~ → ~strike~
    .replace(/\n{3,}/g, '\n\n')                  // collapse excess blank lines
    .trim();
}

// Agent emoji mapping
const AGENT_EMOJI = {
  kevin: ':briefcase:',
  jason: ':scales:',
  scaachi: ':pencil:',
  christian: ':compass:',
  chidi: ':bulb:'
};

const ollamaResp = $input.first().json;
const parsed = $('Route Event').first().json;

const content = ollamaResp.message?.content || 'No response.';
const MAX = 2800;
const formatted = mdToMrkdwn(content);
const truncated = formatted.length > MAX
  ? formatted.slice(0, MAX) + '\n_[truncated — use /ai for full response]_'
  : formatted;

const emoji = AGENT_EMOJI[parsed.agent] || ':robot_face:';
const blocks = [];

if (parsed.isTask) {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: ':white_check_mark: ' + parsed.agent + ' — task complete', emoji: true }
  });
  if (parsed.taskTitle) {
    blocks.push({
      type: 'context',
      elements: [{ type: 'mrkdwn', text: '_' + parsed.taskTitle.slice(0, 100) + '_' }]
    });
  }
} else {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: emoji + ' ' + parsed.agent, emoji: true }
  });
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: 'responding to <@' + parsed.userId + '>' }]
  });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: truncated } });
blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: '_model: ' + (parsed.model || parsed.agent + ':latest') + '_' }]
});

return [{ json: {
  channelId: parsed.channelId,
  thread_ts: parsed.ts,
  payload: JSON.stringify({
    channel: parsed.channelId,
    thread_ts: parsed.ts,
    blocks
  })
}}];
